f=open('readlead.html','r')
h=f.read()
f.close()
old='function editLevel(id){\nvar stu=students.find(function(s){return s.id==id;});\nif(!stu)return;\nvar options=Object.keys(LM).map(function(l){return l+" ("+LM[l][0]+")";}).join("\\n");\nvar newLevel=prompt("Current: "+stu.level+" ("+LM[stu.level][0]+")\\n\\nChoose a new level:\\n"+options);\nif(!newLevel)return;\nnewLevel=newLevel.trim();\nif(newLevel.indexOf("(")<0&&!LM[newLevel]){\nnewLevel="Level "+newLevel.replace(/[^0-9]/g,"");\n}\nif(newLevel.indexOf("(")>0)newLevel=newLevel.split("(")[0].trim();\nif(!LM[newLevel]){alert("Invalid. Please type exactly e.g. Level 5");return;}\nvar idx=students.findIndex(function(s){return s.id==id;});\nstudents[idx].level=newLevel;\nstudents[idx].grade=LM[newLevel][0];\nsaveStudents();\nrdDash();\nloadDashCurr();\n}'
new='function editLevel(id){\nvar stu=students.find(function(s){return s.id==id;});\nif(!stu)return;\nvar overlay=document.createElement("div");\noverlay.style="position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.5);z-index:999;display:flex;align-items:center;justify-content:center;";\nvar box=document.createElement("div");\nbox.style="background:#fff;border-radius:16px;padding:24px;width:320px;max-height:80vh;overflow-y:auto;";\nbox.innerHTML="<div style=\'font-size:16px;font-weight:700;margin-bottom:4px\'>Edit Reading Level</div><div style=\'font-size:13px;color:#888;margin-bottom:16px\'>"+stu.name+" - currently "+stu.level+"</div>";\nObject.keys(LM).forEach(function(l){\nvar btn=document.createElement("button");\nvar grade=LM[l][0];\nvar sublevel=LM[l][1];\nbtn.style="display:block;width:100%;text-align:left;padding:10px 14px;margin-bottom:6px;border-radius:10px;border:2px solid "+(l===stu.level?"#4ECDC4":"#E8E8E8")+";background:"+(l===stu.level?"#4ECDC422":"#fff")+";font-size:13px;font-weight:600;cursor:pointer;";\nbtn.textContent=l+" - "+sublevel+" ("+grade+")";\nbtn.addEventListener("click",function(){\nvar idx=students.findIndex(function(s){return s.id==id;});\nstudents[idx].level=l;\nstudents[idx].grade=LM[l][0];\nsaveStudents();\ndocument.body.removeChild(overlay);\nrdDash();\nloadDashCurr();\n});\nbox.appendChild(btn);\n});\nvar cancel=document.createElement("button");\ncancel.textContent="Cancel";\ncancel.style="width:100%;padding:10px;margin-top:8px;border:none;border-radius:10px;background:#F5F3EE;font-weight:700;cursor:pointer;";\ncancel.addEventListener("click",function(){document.body.removeChild(overlay);});\nbox.appendChild(cancel);\noverlay.appendChild(box);\ndocument.body.appendChild(overlay);\n}'
print('found:',old in h)
h=h.replace(old,new)
open('readlead.html','w').write(h)
print('done')